#include <stdio.h>
#include <stdlib.h>

void global_thresholding(int *image, int width, int height, int initial_threshold) {
  // Initialize threshold and convergence criterion
  float T = initial_threshold;
  float delta = 0.5;

  while (1) {
    // Segment image using current threshold
    int *binary_image = (int *)malloc(width * height * sizeof(int));
    for (int i = 0; i < width * height; i++) {
      binary_image[i] = (image[i] > T) ? 1 : 0;
    }

    // Compute mean intensities for pixel groups
    float m1 = 0, m2 = 0;
    int count1 = 0, count2 = 0;
    for (int i = 0; i < width * height; i++) {
      if (binary_image[i] == 1) {
        m1 += image[i];
        count1++;
      } else {
        m2 += image[i];
        count2++;
      }
    }
    m1 /= count1;
    m2 /= count2;

    // Compute new threshold
    float new_T = (m1 + m2) / 2;

    // Check for convergence
    if (abs(new_T - T) < delta) {
      break;
    }

    // Update threshold
    T = new_T;

    free(binary_image);
  }
}

int main() {
  // Load grayscale image
  int width = 512, height = 512;
  int *image = (int *)malloc(width * height * sizeof(int));
  // ... load image data ...

  // Apply global thresholding
  global_thresholding(image, width, height, 128);

  free(image);
  return 0;
}
